import React, { useState, useEffect } from 'react';
import { Ionicons } from '@expo/vector-icons';
import { WeatherCode, WeatherIconStyle, WeatherIconVariant, weatherCodeToIconName } from './weatherIconTypes';
import LottieView from 'lottie-react-native';

// Type for weather conditions
export type WeatherIconCode =
  | '01d' | '01n' // clear sky
  | '02d' | '02n' // few clouds
  | '03d' | '03n' // scattered clouds
  | '04d' | '04n' // broken clouds
  | '09d' | '09n' // shower rain
  | '10d' | '10n' // rain
  | '11d' | '11n' // thunderstorm
  | '13d' | '13n' // snow
  | '50d' | '50n'; // mist

// Type guard to check if a string is a valid weather icon code
export const isValidWeatherCode = (code: string): code is WeatherIconCode => {
  return Object.keys(weatherIconMap).includes(code);
};

export type IoniconsName = React.ComponentProps<typeof Ionicons>['name'];

// Map OpenWeather codes to Ionicons
export const weatherIconMap: Record<WeatherIconCode, IoniconsName> = {
  // Clear
  '01d': 'sunny-outline',
  '01n': 'moon-outline',

  // Few clouds
  '02d': 'partly-sunny-outline',
  '02n': 'cloudy-night-outline',

  // Scattered clouds
  '03d': 'cloud-outline',
  '03n': 'cloud-outline',

  // Broken clouds
  '04d': 'cloudy-outline',
  '04n': 'cloudy-outline',

  // Shower rain
  '09d': 'rainy-outline',
  '09n': 'rainy-outline',

  // Rain
  '10d': 'thunderstorm-outline',
  '10n': 'thunderstorm-outline',

  // Thunderstorm
  '11d': 'thunderstorm-outline',
  '11n': 'thunderstorm-outline',

  // Snow
  '13d': 'snow-outline',
  '13n': 'snow-outline',

  // Mist
  '50d': 'water-outline',
  '50n': 'water-outline',
};

// Helper to get the correct path for an icon
const getIconPath = (
  iconName: string,
  style: WeatherIconStyle,
  variant: WeatherIconVariant
): string => {
  const basePath = '../assets/weather/weather-icons/production';

  if (variant === 'animated') {
    return `${basePath}/${style}/lottie/${iconName}.json`;
  }

  return `${basePath}/${style}/svg-static/${iconName}.svg`;
};

// Dynamic import helper
const importIcon = async (
  weatherCode: WeatherCode,
  style: WeatherIconStyle = 'fill',
  variant: WeatherIconVariant = 'static'
): Promise<any> => {
  const iconName = weatherCodeToIconName[weatherCode];
  const path = getIconPath(iconName, style, variant);

  try {
    return await import(path);
  } catch (error) {
    console.warn(`Failed to load weather icon: ${path}`, error);
    // Return a default icon as fallback
    return await import(getIconPath('clear-day', 'fill', 'static'));
  }
};

interface WeatherIconProps {
  weatherCode: WeatherCode;
  style?: WeatherIconStyle;
  variant?: WeatherIconVariant;
  size?: number;
  color?: string;
}

export const WeatherIcon: React.FC<WeatherIconProps> = ({
  weatherCode,
  style = 'fill',
  variant = 'static',
  size = 24,
  color = '#000'
}) => {
  const [Icon, setIcon] = useState<any>(null);

  useEffect(() => {
    importIcon(weatherCode, style, variant)
      .then(icon => setIcon(icon.default))
      .catch(console.error);
  }, [weatherCode, style, variant]);

  if (!Icon) {
    return null;
  }

  if (variant === 'animated') {
    return React.createElement(LottieView, {
      source: Icon,
      style: { width: size, height: size },
      autoPlay: true,
      loop: true
    });
  }

  return React.createElement(Icon, {
    width: size,
    height: size,
    fill: color
  });
};

// Helper function to determine if it's day or night
export const isDayTime = (iconCode: string): boolean => {
  return iconCode.endsWith('d');
};
